#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int *col;
    int sz;
} Pref;

int cmpCollege(const void *a, const void *b, void *arg) {
    int *rank = (int *)arg;
    int ca = *(int *)a;
    int cb = *(int *)b;
    return rank[ca] - rank[cb];
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d", &N, &M);
        int *colRank = (int*)malloc((N+1)*sizeof(int));
        for(int i=1;i<=N;i++) scanf("%d", &colRank[i]);
        int *studRank = (int*)malloc((M+1)*sizeof(int));
        for(int i=1;i<=M;i++) scanf("%d", &studRank[i]);
        int *byRank = (int*)malloc((M+1)*sizeof(int));
        for(int i=1;i<=M;i++) byRank[studRank[i]] = i;
        Pref *pref = (Pref*)malloc((M+1)*sizeof(Pref));
        for(int i=1;i<=M;i++){
            int k; scanf("%d", &k);
            pref[i].sz = k;
            pref[i].col = (int*)malloc(k*sizeof(int));
            for(int j=0;j<k;j++) scanf("%d", &pref[i].col[j]);
            qsort_r(pref[i].col, k, sizeof(int), cmpCollege, colRank);
        }
        char *taken = (char*)calloc(N+1, sizeof(char));
        int *ans = (int*)calloc(M+1, sizeof(int));
        for(int r=1;r<=M;r++){
            int id = byRank[r];
            int chosen = 0;
            for(int j=0;j<pref[id].sz;j++){
                int c = pref[id].col[j];
                if(!taken[c]){ taken[c]=1; chosen=c; break; }
            }
            ans[id]=chosen;
        }
        printf("%d\n", ans[1]);
        // free memory
        for(int i=1;i<=M;i++) free(pref[i].col);
        free(pref); free(colRank); free(studRank); free(byRank); free(taken); free(ans);
    }
    return 0;
}

