import java.io.*;
import java.util.*;

public class Main {
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return val * sign;
        }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();
        int T = fs.nextInt();
        while (T-- > 0) {
            int N = fs.nextInt();
            int M = fs.nextInt();
            int[] colRank = new int[N+1];
            for (int i=1;i<=N;i++) colRank[i] = fs.nextInt();
            int[] studRank = new int[M+1];
            for (int i=1;i<=M;i++) studRank[i] = fs.nextInt();
            int[] byRank = new int[M+1];
            for (int i=1;i<=M;i++) byRank[studRank[i]] = i;
            @SuppressWarnings("unchecked")
            ArrayList<Integer>[] pref = new ArrayList[M+1];
            for (int i=1;i<=M;i++) {
                int k = fs.nextInt();
                pref[i] = new ArrayList<>(k);
                for (int j=0;j<k;j++) pref[i].add(fs.nextInt());
                pref[i].sort((a,b) -> Integer.compare(colRank[a], colRank[b]));
            }
            boolean[] taken = new boolean[N+1];
            int[] ans = new int[M+1];
            for (int r=1;r<=M;r++) {
                int id = byRank[r];
                for (int c : pref[id]) {
                    if (!taken[c]) { taken[c]=true; ans[id]=c; break; }
                }
            }
            out.append(ans[1]).append('\n');
        }
        System.out.print(out.toString());
    }
}

