const fs = require('fs');
const data = fs.readFileSync(0, 'utf8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = data[idx++];
let output = [];
for (let tc = 0; tc < T; tc++) {
  const N = data[idx++];
  const M = data[idx++];
  const colRank = new Array(N + 1);
  for (let i = 1; i <= N; i++) colRank[i] = data[idx++];
  const studRank = new Array(M + 1);
  for (let i = 1; i <= M; i++) studRank[i] = data[idx++];
  const byRank = new Array(M + 1);
  for (let i = 1; i <= M; i++) byRank[studRank[i]] = i;
  const pref = new Array(M + 1);
  for (let i = 1; i <= M; i++) {
    const k = data[idx++];
    const arr = new Array(k);
    for (let j = 0; j < k; j++) arr[j] = data[idx++];
    arr.sort((a, b) => colRank[a] - colRank[b]);
    pref[i] = arr;
  }
  const taken = new Array(N + 1).fill(false);
  const ans = new Array(M + 1).fill(0);
  for (let r = 1; r <= M; r++) {
    const sid = byRank[r];
    const list = pref[sid];
    for (let c of list) {
      if (!taken[c]) { taken[c] = true; ans[sid] = c; break; }
    }
  }
  output.push(String(ans[1]));
}
